create table carrier (id bigint generated by default as identity primary key, carrier_code varchar(32) not null, carrier_name varchar(128) not null, webhook_secret varchar(255) not null, query_base_url varchar(255), enabled boolean not null default true, created_at timestamp not null, updated_at timestamp not null, constraint uk_carrier_code unique(carrier_code));
create table carrier_status_mapping (id bigint generated by default as identity primary key, carrier_id bigint not null, raw_status varchar(64) not null, normalized_status varchar(64) not null, enabled boolean not null default true, created_at timestamp not null, updated_at timestamp not null, constraint uk_mapping unique(carrier_id, raw_status), constraint fk_mapping_carrier foreign key(carrier_id) references carrier(id));
create table shipment (id bigint generated by default as identity primary key, tracking_no varchar(64) not null, carrier_id bigint not null, business_order_no varchar(64), current_status varchar(64) not null, current_status_event_time timestamp, last_received_time timestamp, max_event_time timestamp, has_open_anomaly boolean not null default false, version int not null default 0, created_at timestamp not null, updated_at timestamp not null, constraint uk_shipment unique(carrier_id, tracking_no), constraint fk_shipment_carrier foreign key(carrier_id) references carrier(id));
create index idx_shipment_status on shipment(current_status, carrier_id, created_at);
create table raw_carrier_event (id bigint generated by default as identity primary key, carrier_id bigint not null, shipment_id bigint not null, tracking_no varchar(64) not null, external_event_id varchar(128), idempotency_key varchar(128) not null, event_fingerprint varchar(128) not null, raw_status varchar(64) not null, raw_body clob not null, request_headers clob, signature_valid boolean not null, received_time timestamp default current_timestamp, process_status varchar(32) not null, failure_reason varchar(500), created_at timestamp not null, updated_at timestamp not null, constraint uk_raw_idempotency unique(carrier_id, idempotency_key), constraint fk_raw_carrier foreign key(carrier_id) references carrier(id), constraint fk_raw_shipment foreign key(shipment_id) references shipment(id));
create index idx_raw_tracking_time on raw_carrier_event(tracking_no, received_time);
create table normalized_event (id bigint generated by default as identity primary key, shipment_id bigint not null, carrier_id bigint not null, raw_event_id bigint, external_event_id varchar(128), normalized_status varchar(64) not null, raw_status varchar(64) not null, event_time timestamp not null, received_time timestamp not null, location varchar(255), description varchar(500), source varchar(32) not null, late_arrival boolean not null, applied_to_state boolean not null, validation_status varchar(32) not null, event_fingerprint varchar(128) not null, created_at timestamp not null, constraint uk_normalized_raw unique(raw_event_id), constraint uk_normalized_fingerprint unique(event_fingerprint), constraint fk_ne_shipment foreign key(shipment_id) references shipment(id), constraint fk_ne_carrier foreign key(carrier_id) references carrier(id));
create index idx_ne_timeline on normalized_event(shipment_id, event_time);
create table event_process_task (id bigint generated by default as identity primary key, raw_event_id bigint not null, task_key varchar(128) not null, status varchar(32) not null, retry_count int not null, max_retry_count int not null, next_retry_time timestamp, locked_at timestamp, locked_by varchar(64), message_sent_at timestamp, last_error varchar(500), created_at timestamp not null, updated_at timestamp not null, constraint uk_task_key unique(task_key), constraint fk_task_raw foreign key(raw_event_id) references raw_carrier_event(id));
create index idx_task_status_next on event_process_task(status, next_retry_time);
create table shipment_anomaly (id bigint generated by default as identity primary key, shipment_id bigint not null, anomaly_type varchar(64) not null, business_key varchar(160) not null, severity varchar(16) not null, status varchar(32) not null, rule_code varchar(64) not null, evidence_event_id bigint, description varchar(500) not null, resolution_note varchar(500), detected_at timestamp not null, resolved_at timestamp, created_at timestamp not null, updated_at timestamp not null, constraint uk_anomaly_key unique(business_key), constraint fk_anomaly_shipment foreign key(shipment_id) references shipment(id));
create index idx_anomaly_status on shipment_anomaly(status, anomaly_type, detected_at);
create table reconciliation_batch (id bigint generated by default as identity primary key, batch_no varchar(64) not null unique, trigger_type varchar(32) not null, status varchar(32) not null, total_count int not null, success_count int not null, failed_count int not null, difference_count int not null, inserted_event_count int not null, started_at timestamp, completed_at timestamp, created_at timestamp not null, updated_at timestamp not null);
create table reconciliation_task (id bigint generated by default as identity primary key, batch_id bigint not null, shipment_id bigint not null, task_key varchar(128) not null, status varchar(32) not null, retry_count int not null, max_retry_count int not null, next_retry_time timestamp, before_status varchar(64), remote_status varchar(64), after_status varchar(64), difference_found boolean not null, inserted_event_count int not null, last_error varchar(500), started_at timestamp, completed_at timestamp, created_at timestamp not null, updated_at timestamp not null, constraint uk_reconciliation_task unique(task_key), constraint fk_rt_batch foreign key(batch_id) references reconciliation_batch(id), constraint fk_rt_shipment foreign key(shipment_id) references shipment(id));
create index idx_rt_batch_status on reconciliation_task(batch_id, status);
create table operation_log (id bigint generated by default as identity primary key, operation_type varchar(64) not null, resource_type varchar(64) not null, resource_id bigint, operator_name varchar(64), request_id varchar(128), summary varchar(500), created_at timestamp not null);
